/* 是否是手機號 */
export function isMobile(str) {
  // const reg = /^(((13[0-9]{1})|(15[0-9]{1})|(18[0-9]{1}))+\d{8})$/
  const reg = /^1\d{10}$|^[0][9]\d{8}$/
  return reg.test(str.trim())
}

